  ('cpa-moex-00761', 'cpa', 'cpa-moex-108-9bdab6d6', 'sub-cpa-05', NULL, 'single_choice', '依所得稅法及相關法規規定，下列何項應「全額」納入個人綜合所得總額之「薪資」所得中課稅？ 董監事酬勞    加班費 員工行使認股權於實際出售時所獲取之所得  差旅費', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:10+00:00", "source_pdf_sha1": "2689da149a8e", "answer_pdf_sha1": "68437cc80423", "source_family": "moex-gov-tw", "moex": {"exam_code": "108140", "c": "803", "s": "0203", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "108", "exam_name": "108年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 2, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
