  ('cpa-moex-00763', 'cpa', 'cpa-moex-108-9bdab6d6', 'sub-cpa-05', NULL, 'single_choice', '依所得稅法規定，下列何者應課徵所得稅？ 委託人將信託財產移轉給受託人 信託關係存續中受託人變更，信託財產由原受託人移轉給新受託人 信託關係存續中，受託人管理或處分信託財產發生之所得 信託關係消滅，受託人將信託財產移轉給受益人', '["", "", "", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:10+00:00", "source_pdf_sha1": "2689da149a8e", "answer_pdf_sha1": "68437cc80423", "source_family": "moex-gov-tw", "moex": {"exam_code": "108140", "c": "803", "s": "0203", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "108", "exam_name": "108年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 4, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00764', 'cpa', 'cpa-moex-108-9bdab6d6', 'sub-cpa-05', NULL, 'single_choice', '非中華民國境內居住之個人約翰先生107年度取得非屬扣繳範圍之所得，設約翰先生在108年3 月31日離境，依所得稅法相關規定，該非屬扣繳範圍之所得應如何履行綜合所得稅納稅義務？ 免扣繳也免申報納稅 離境前依規定稅率申報納稅 於綜合所得稅申報期限內採與居住者相同方式結算申報 於108年再入境時補申報', '["", "", "", ""]'::jsonb, 1, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:10+00:00", "source_pdf_sha1": "2689da149a8e", "answer_pdf_sha1": "68437cc80423", "source_family": "moex-gov-tw", "moex": {"exam_code": "108140", "c": "803", "s": "0203", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "108", "exam_name": "108年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 5, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00765', 'cpa', 'cpa-moex-108-9bdab6d6', 'sub-cpa-05', NULL, 'single_choice', '依加值型及非加值型營業稅法規定，下列何者適用零稅率？ 保稅區廠商銷售電腦與課稅區廠商並指定運送至其營業場所而取得之收入 銷售生鮮農產品而取得之收入 廠商介紹國內買主予國外供應商而向國內買主收取之佣金 課稅區廠商為保稅區之外銷晶圓廠商代工、檢驗而取得之收入', '["", "", "", ""]'::jsonb, 3, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:10+00:00", "source_pdf_sha1": "2689da149a8e", "answer_pdf_sha1": "68437cc80423", "source_family": "moex-gov-tw", "moex": {"exam_code": "108140", "c": "803", "s": "0203", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "108", "exam_name": "108年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 6, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00766', 'cpa', 'cpa-moex-108-9bdab6d6', 'sub-cpa-05', NULL, 'single_choice', '依加值型及非加值型營業稅法規定，營業人申報之溢付稅額，下列何者不得申請退還？ 銷售適用零稅率貨物而溢付之營業稅 取得固定資產而溢付之營業稅 建設公司購買備供出售之房屋而溢付之營業稅 解散或廢止申請註銷登記而溢付之營業稅', '["", "", "", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:10+00:00", "source_pdf_sha1": "2689da149a8e", "answer_pdf_sha1": "68437cc80423", "source_family": "moex-gov-tw", "moex": {"exam_code": "108140", "c": "803", "s": "0203", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "108", "exam_name": "108年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 7, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00767', 'cpa', 'cpa-moex-108-9bdab6d6', 'sub-cpa-05', NULL, 'single_choice', '依加值型及非加值型營業稅法規定，採加值型計算稅額的營業人，下列何項進項稅額不得扣抵銷 項稅額？ 員工旅遊支付飯店之住宿費  購買捐贈政府機關之日用品 促銷活動隨貨贈送之贈品  汽車出租業購置供出租使用之五人座小汽車', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:10+00:00", "source_pdf_sha1": "2689da149a8e", "answer_pdf_sha1": "68437cc80423", "source_family": "moex-gov-tw", "moex": {"exam_code": "108140", "c": "803", "s": "0203", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "108", "exam_name": "108年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 8, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00768', 'cpa', 'cpa-moex-108-9bdab6d6', 'sub-cpa-05', NULL, 'single_choice', '依加值型及非加值型營業稅法之規定，營業人若同時設有總機構及分支機構者，其有關稅籍登記 應如何辦理？ 由總機構代為申請稅籍登記即可，該等分支機構無須自行申請稅籍登記 僅總機構須申請稅籍登記，該等分支機構無須另行個別申請稅籍登記 總機構須申請稅籍登記，該等分支機構亦須自行申請稅籍登記 皆無須申請稅籍登記', '["", "", "", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:10+00:00", "source_pdf_sha1": "2689da149a8e", "answer_pdf_sha1": "68437cc80423", "source_family": "moex-gov-tw", "moex": {"exam_code": "108140", "c": "803", "s": "0203", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "108", "exam_name": "108年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 9, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00769', 'cpa', 'cpa-moex-108-9bdab6d6', 'sub-cpa-05', NULL, 'single_choice', '土地所有權人出售土地後，另行購買土地，合於規定者，得申請退還已納土地增值稅，依土地稅 法規定，下列敘述何者錯誤？ 適用於自用住宅用地、自營工廠用地及自耕之農業用地 土地所有權人先購買土地後，自完成移轉登記之日起2年內，始行出售土地者，準用退還之規定 重購之土地，自完成移轉登記之日起，5年內再行移轉，應追繳原退還稅款 應向重購土地所在地之稽徵機關辦理退還申請', '["", "", "", ""]'::jsonb, 3, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:10+00:00", "source_pdf_sha1": "2689da149a8e", "answer_pdf_sha1": "68437cc80423", "source_family": "moex-gov-tw", "moex": {"exam_code": "108140", "c": "803", "s": "0203", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "108", "exam_name": "108年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 10, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00770', 'cpa', 'cpa-moex-108-9bdab6d6', 'sub-cpa-05', NULL, 'single_choice', '經依復查、訴願或行政訴訟程序終結決定或判決有應補繳稅額者，除填發補稅單外，應依下列何 種利率按日加計利息一併徵收？ 按該決定或判決日當日郵政儲金一年期定期儲金固定利率 按該決定或判決日當年度郵政儲金一年期定期儲金固定利率 按各年度一月一日臺灣銀行一年期定期儲金固定利率 按各年度一月一日郵政儲金一年期定期儲金固定利率', '["", "", "", ""]'::jsonb, 3, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:10+00:00", "source_pdf_sha1": "2689da149a8e", "answer_pdf_sha1": "68437cc80423", "source_family": "moex-gov-tw", "moex": {"exam_code": "108140", "c": "803", "s": "0203", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "108", "exam_name": "108年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 11, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL)
